mapper.select:
SELECT ISNULL(TIA1.PlainText,'Untitled') AS ItemName , TI.Identifier , TIC.Icon , TI.ItemID AS id , TI.ProjectID
, TIA4.LovCode As DoneStatus , TIA5.PlainText As dept , MN2.MAP_VAXIS , MN2.CD_MAP_VAXIS As LovCode FROM XBOLTADM.TB_ITEM TI WITH (NOLOCK) INNER Join XBOLTADM.TB_ITEM_CLASS TIC WITH (NOLOCK) ON TIC.ItemClassCode = TI.ClassCode Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA1 WITH (NOLOCK) ON TIA1.ItemID = TI.ItemID And TIA1.AttrTypeCode = 'AT00001' And TIA1.LanguageID =#{languageID}
Left Outer Join OLM.DZK0.V_DZKDT_P_STD_MNBODY2 MN2 WITH (NOLOCK) on CONCAT(MN2.ID_ACTY, '_', MN2.NO_STD_MNAL)= TI.Identifier
Left Outer Join OLM.DZK0.V_DZKDT_P_SITE_MNBODY2 MN2 WITH (NOLOCK) on CONCAT(MN2.ID_ACTY, '_', MN2.CD_SITE)= TI.Identifier
Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA4 WITH (NOLOCK) ON TIA4.ItemID = TI.ItemID And TIA4.AttrTypeCode = 'ZPAT030' And TIA4.LanguageID =#{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA5 WITH (NOLOCK) ON TIA5.ItemID = TI.ItemID And TIA5.AttrTypeCode = 'ZAT0003' And TIA5.LanguageID =#{languageID} WHERE TI.ItemID = #{s_itemID}

		SELECT
			IT.ItemID AS p_itemID,
			IT.Identifier,
			IT.ClassCode,
			IT.ItemTypeCode,
			TD.Name as ClassName,
			IATR.PlainText AS ItemName,
			TIA4.LovCode As DoneStatus,
			MN2.MAP_VAXIS As Value,
			MN2.CD_MAP_VAXIS As LovCode

		FROM XBOLTADM.TB_ITEM IT
			Left outer join XBOLTADM.TB_ITEM_ATTR IATR WITH (NOLOCK) on IT.ItemID = IATR.ItemID and IATR.AttrTypeCode = 'AT00001' And IATR.LanguageID =#{languageID}
			
			
			Left outer join XBOLTADM.TB_DICTIONARY TD WITH (NOLOCK) on IT.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA3 WITH (NOLOCK) ON TIA3.ItemID = IT.ItemID And TIA3.AttrTypeCode = 'ZPAT007' And TIA3.LanguageID =#{languageID}
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA4 WITH (NOLOCK) ON TIA4.ItemID = IT.ItemID And TIA4.AttrTypeCode = 'ZPAT030' And TIA4.LanguageID =#{languageID}
			
				
					Left Outer Join OLM.DZK0.V_DZKDT_P_STD_MNBODY2 MN2 WITH (NOLOCK) on CONCAT(MN2.ID_ACTY, '_', MN2.NO_STD_MNAL)= IT.Identifier	
				
				
					Left Outer Join OLM.DZK0.V_DZKDT_P_SITE_MNBODY2 MN2 WITH (NOLOCK) on CONCAT(MN2.ID_ACTY, '_', MN2.CD_SITE)= IT.Identifier		
				
			
			
			
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 WITH (NOLOCK) ON TIA5.ItemID = IT.ItemID AND TIA5.AttrTypeCode = 'ZPAT016' AND TIA5.LanguageID = #{languageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA8 WITH (NOLOCK) ON TIA8.ItemID = IT.ItemID AND TIA8.AttrTypeCode = 'ZPAT015' AND TIA8.LanguageID = #{languageID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR MyATR WITH (NOLOCK) ON MyATR.AttrTypeCode = TIA8.AttrTypeCode AND MyATR.ItemID = #{my_itemID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR MyATR1 WITH (NOLOCK) ON MyATR1.AttrTypeCode = TIA5.AttrTypeCode AND MyATR1.ItemID = #{my_itemID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA10 WITH (NOLOCK) ON TIA10.ItemID = IT.ItemID AND TIA10.AttrTypeCode = 'ZAT0003' AND TIA10.LanguageID = #{languageID}
			
			WHERE Identifier in
			(
			SELECT s.items
			FROM XBOLTADM.TB_ITEM_ATTR ATR WITH (NOLOCK)
			CROSS APPLY XBOLTADM.fn_SplitAndTrim(ATR.PlainText, CHAR(44)) s
			WHERE ATR.ItemID = #{s_itemID} AND ATR.AttrTypeCode = 'ZPAT011'
			)
			AND IT.ItemID != #{s_itemID} AND IT.ProjectID = #{projectID}
			
			    AND TRY_CAST(TIA5.PlainText AS INT) >= (TRY_CAST(MyATR1.PlainText AS INT) - ${month})
				AND TRY_CAST(TIA5.PlainText AS INT) <= TRY_CAST(MyATR1.PlainText AS INT)

	
		SELECT DISTINCT
		    IT.ItemID AS p_itemID,
			postItem.itemID AS usedItemID,
			s.items AS myItemIdentifier,
			ITT.ClassCode,
		    ITT.ItemTypeCode,
		    ATTR.PlainText as ItemName,
			MN2.MAP_VAXIS As Value,
			MN2.CD_MAP_VAXIS As LovCode,
		   
		    TIA4.LovCode AS DoneStatus
	
		FROM XBOLTADM.TB_ITEM ITT WITH (NOLOCK)
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR postItem WITH (NOLOCK) ON postItem.ItemID = ITT.itemID AND postItem.AttrTypeCode = 'ZPAT036' AND postItem.LanguageID = #{languageID}	
		CROSS APPLY XBOLTADM.fn_SplitAndTrim(postItem.PlainText, CHAR(44)) s
		LEFT JOIN XBOLTADM.TB_ITEM IT WITH (NOLOCK) ON IT.Identifier  = s.items  AND IT.Deleted != 1
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR ATTR WITH (NOLOCK) ON IT.ItemID = ATTR.ItemID AND ATTR.AttrTypeCode = 'AT00001' AND ATTR.LanguageID = #{languageID}	
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 WITH (NOLOCK) ON TIA3.ItemID = IT.itemID AND TIA3.AttrTypeCode = 'ZPAT007' AND TIA3.LanguageID = #{languageID}	
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA4 WITH (NOLOCK) ON TIA4.ItemID = IT.itemID AND TIA4.AttrTypeCode = 'ZPAT030' AND TIA4.LanguageID = #{languageID}
		
			
				Left Outer Join OLM.DZK0.V_DZKDT_P_STD_MNBODY2 MN2 WITH (NOLOCK) on CONCAT(MN2.ID_ACTY, '_', MN2.NO_STD_MNAL)= ITT.Identifier	
			
			
				Left Outer Join OLM.DZK0.V_DZKDT_P_SITE_MNBODY2 MN2 WITH (NOLOCK) on CONCAT(MN2.ID_ACTY, '_', MN2.CD_SITE)= ITT.Identifier		
			
			 			
		
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA5 WITH (NOLOCK) ON TIA5.ItemID = IT.itemID AND TIA5.AttrTypeCode = 'ZPAT016' AND TIA5.LanguageID = #{languageID}	
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA8 WITH (NOLOCK) ON TIA8.ItemID = IT.itemID AND TIA8.AttrTypeCode = 'ZPAT015' AND TIA8.LanguageID = #{languageID}	
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA10 WITH (NOLOCK) ON TIA10.ItemID = IT.itemID AND TIA10.AttrTypeCode = 'ZAT0003' AND TIA10.LanguageID = #{languageID}	
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR MyATR WITH (NOLOCK) ON MyATR.AttrTypeCode = TIA8.AttrTypeCode AND MyATR.ItemID = #{my_itemID}
		LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR MyATR1 WITH (NOLOCK) ON MyATR1.AttrTypeCode = TIA5.AttrTypeCode AND MyATR1.ItemID = #{my_itemID}
		
		
		WHERE ITT.ItemID = #{itemID}  AND ITT.ProjectID = #{projectID}  
		
			AND TRY_CAST(TIA5.PlainText AS INT) >= TRY_CAST(MyATR1.PlainText AS INT)
	   		AND TRY_CAST(TIA5.PlainText AS INT) <= (TRY_CAST(MyATR1.PlainText AS INT) + ${month})

SELECT PJCategory 
From XBOLTADM.TB_PROJECT WITH (NOLOCK)
WHERE ProjectCode = #{projectCode}

mapper.update:
UPDATE XBOLTADM.TB_VISIT_LOG
SET ActionType = #{ActionType}
WHERE MenuID = #{BatName}
AND Comment = #{ExecDate}
AND ItemID = #{ItemID}

mapper.select:
Select TMT.IsModel From XBOLTADM.TB_MODEL_TYPE TMT WITH (NOLOCK)
LEFT OUTER JOIN XBOLTADM.TB_MODEL TM WITH (NOLOCK) ON TMT.ModelTypeCode = TM.ModelTypeCode 
Where TM.ModelID = #{modelID}

select PPJT.ProjectCode 
from XBOLTADM.TB_ITEM ITM WITH (NOLOCK)
LEFT JOIN XBOLTADM.TB_PROJECT PJT WITH (NOLOCK) ON ITM.ProjectID = PJT.ProjectID
LEFT JOIN XBOLTADM.TB_PROJECT PPJT WITH (NOLOCK) ON PJT.ParentID = PPJT.ProjectID  
where itemid = #{itemID}

mapper.update:
UPDATE XBOLTADM.TB_BATCH_JOB_LOG
SET Status = #{Status}, EndTime = GETDATE()
WHERE BatchJobNo = #{BatchJobNo}
